// EP-152 and EP-153: random Sidon sets at larger size for A+A run stats.
{
  const rng = makeRng(20260304 ^ 152);
  const N = 60000;
  const targetSizes = [80, 100, 120];
  const rows = [];

  for (const m of targetSizes) {
    let bestIso = null;
    let bestGap = null;
    for (let r = 0; r < 20; r += 1) {
      const A = sidonGreedyRandom(N, m, rng, 20);
      if (A.length < m) continue;
      const stats = computeAAStats(A);
      const row = {
        m,
        isolated: stats.isolated,
        avg_sq_gap: Number(stats.avgSqGap.toPrecision(6)),
        t: stats.t,
      };
      if (!bestIso || row.isolated < bestIso.isolated) bestIso = row;
      if (!bestGap || row.avg_sq_gap < bestGap.avg_sq_gap) bestGap = row;
    }
    if (bestIso && bestGap) rows.push({
      m,
      best_isolated: bestIso.isolated,
      best_isolated_avg_sq_gap: bestIso.avg_sq_gap,
      best_avg_sq_gap: bestGap.avg_sq_gap,
      best_avg_sq_gap_isolated: bestGap.isolated,
      t: bestIso.t,
    });
  }

  out.results.ep152_ep153 = {
    description: 'Random-greedy Sidon sets for larger m; report best isolated count and best avg squared gap (separately) in A+A.',
    N,
    rows,
  };
}
